module RefModule 
(
  input rst,
  input clk,
  input up,
  input down,

  output reg [2:0] count
);

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
    if (rst) 
	begin
      count <= 3'b000;
    end 
	else if (up) 
	begin
      count <= count + 1;
    end 
	else if (down) 
	begin
      count <= count - 1;
    end
  end

endmodule
